const ev = $json;
const p = ev.payload || {};
const parts = [
  'commitment of traders COT positioning',
  p.signal || '',
  p.signal === 'extreme_long' || p.signal === 'bullish' ? 'smart money accumulation commercials buying' : '',
  p.signal === 'extreme_short' || p.signal === 'bearish' ? 'distribution commercials selling crowded long' : '',
  ev.instrument || p.commodity || '',
  p.large_spec_pct_rank != null ? 'pct rank ' + p.large_spec_pct_rank : '',
  'speculators commercials net position'
];
const q = parts.filter(Boolean).join(' ').trim();
return { json: { ...ev, rag_query: q.slice(0, 500) } };

const ev = $('Build RAG query').first().json;
const p = ev.payload || {};
const reportDate = p.report_date;
let ageDays = null;
if (reportDate) {
  ageDays = Math.floor((Date.now() - new Date(reportDate).getTime()) / 86400000);
}
return { json: { ...ev, payload: { ...p, _report_age_days: ageDays } } };

parameters.query:
SELECT event_id, event_instrument, event_payload, book_slug, chunk_idx, title, content, score FROM (
                    SELECT '{{ $('Annotate age').first().json.event_id }}'::uuid AS event_id,
                           '{{ $('Annotate age').first().json.instrument || '' }}' AS event_instrument,
                           '{{ JSON.stringify($('Annotate age').first().json.payload) }}'::jsonb AS event_payload
                ) ev
                CROSS JOIN LATERAL search_knowledge(('[' || '{{ $json.embedding.values.join(',') }}' || ']')::vector, 3);

parameters.jsCode:
const event = $('Annotate age').first().json;
const chunks = items.map(i => i.json).filter(c => c.content);

const contextBlocks = chunks.slice(0, 3).map((c, i) =>
  `[${i + 1}] ${c.book_slug}/${c.chunk_idx} (score=${Number(c.score).toFixed(2)})\n${c.content}`
).join('\n\n---\n\n');

const systemPrompt = `You are PositioningAgent, a specialist analyst focused on Commitment of Traders (COT) and institutional positioning. Input: a positioning event (weekly COT report snapshot for a commodity/index). Output: ONE structured trade signal JSON — or {"skip": true, "reason": "..."} if no actionable setup.

MANDATORY CHECKS (in order):
1. If payload._report_age_days == null OR payload._report_age_days > 21 → skip with reason "stale COT report: age " + payload._report_age_days + " days"
2. If payload.signal == "neutral" AND Math.abs(payload.large_spec_pct_rank - 50) < 15 → skip with reason "no positioning extreme"
3. Otherwise analyze positioning divergence vs price implication

Framework (apply in order of priority):
- Contrarian extremes: large specs at pct_rank >= 90 = crowded long (bearish contrarian); <= 10 = crowded short (bullish contrarian)
- Commercials are smart money: their net position divergence from specs signals reversal zones
- Signal tiers:
  * extreme_long (specs >= 90 pct) + commercials net short → HIGH conviction FADE (short setup)
  * extreme_short (specs <= 10 pct) + commercials net long → HIGH conviction FADE (long setup)
  * bullish (specs >= 75) WITHOUT commercial confirmation → WEAK setup, lean skip
  * weekly_change sign flip + pct_rank crossing 50 → momentum shift, moderate conviction
- Timeframe: COT is weekly → bias is swing/position (1W-1M horizon), never intraday
- Van Tharp R-multiple: positioning trades need wider stops (2-3 ATR), target 2-4R
- NO fixed entry/SL/TP numbers (no live price available) — set entry/sl/tp to null; describe levels qualitatively in rationale

Signal schema — return ONLY this JSON, no commentary:
{
  "instrument": "string",
  "timeframe": "1W|1M",
  "bias": "long|short|flat",
  "confidence": 0.0-1.0,
  "entry": null,
  "sl": null,
  "tp": null,
  "r_multiple": null,
  "rationale": "one sentence: positioning state + divergence + implication",
  "knowledge_refs": ["book_slug/chunk_idx", ...],
  "strategy_tag": "cot-extreme-fade|cot-commercials-divergence|cot-momentum-shift|..."
}
Or: {"skip": true, "reason": "stale COT report..." | "no positioning extreme" | "no setup"}`;

const userPrompt = `POSITIONING EVENT
source: ${event.source}
instrument: ${event.instrument || 'n/a'}
payload: ${JSON.stringify(event.payload)}

RETRIEVED KNOWLEDGE
${contextBlocks}

Output the signal JSON now.`;

return [{
  json: {
    event_id: event.event_id,
    event_instrument: event.instrument,
    event_payload: event.payload,
    systemPrompt,
    userPrompt,
    knowledge_refs: chunks.slice(0, 3).map(c => `${c.book_slug}/${c.chunk_idx}`)
  }
}];

const ctx = $('Build Gemini Prompt').first().json;
const resp = items[0].json;
return [{ json: { ...resp, event_id: ctx.event_id, event_payload: ctx.event_payload, knowledge_refs: ctx.knowledge_refs } }];

const resp = items[0].json;
let text = '';
try { text = resp.candidates[0].content.parts[0].text; }
catch (e) { return [{ json: { skip: true, reason: 'no candidates', event_id: resp.event_id } }]; }

text = text.replace(/```json\s*/gi, '').replace(/```/g, '').trim();

let signal;
try { signal = JSON.parse(text); }
catch (e) { return [{ json: { skip: true, reason: 'parse fail: ' + text.slice(0,100), event_id: resp.event_id } }]; }

if (signal.skip) {
  return [{ json: { skip: true, reason: signal.reason, event_id: resp.event_id } }];
}

const required = ['instrument', 'timeframe', 'bias', 'confidence'];
for (const k of required) {
  if (!(k in signal)) return [{ json: { skip: true, reason: 'missing ' + k, event_id: resp.event_id } }];
}

const effective_refs = (signal.knowledge_refs && signal.knowledge_refs.length ? signal.knowledge_refs : (resp.knowledge_refs || []));


return [{
    json: {
      skip: false,
    event_id: resp.event_id,
    instrument: signal.instrument,
    timeframe: signal.timeframe,
    bias: signal.bias,
    confidence: Number(signal.confidence),
    entry: signal.entry ?? null,
    sl: signal.sl ?? null,
    tp: signal.tp || null,
    r_multiple: signal.r_multiple ?? null,
    rationale: { positioning: signal.rationale || '' },
    knowledge_refs: effective_refs,
    strategy_tag: signal.strategy_tag || 'cot-positioning',
    telegram_text: `[POS] ${signal.bias === 'long' ? 'LONG' : signal.bias === 'short' ? 'SHORT' : 'FLAT'} ${signal.instrument} ${signal.timeframe}
confidence: ${Number(signal.confidence).toFixed(2)}
strategy: ${signal.strategy_tag || 'cot-positioning'}
why: ${signal.rationale || ''}
refs: ${effective_refs.join(', ')}`
  }
}];

